import { HighlightItem } from './highlight-item';
import { ResetHighlightItem } from './reset-highlight-item';
import { DisableItem } from './disable-item';
import { HighlightSeries } from '../highlight-series';
import { d3_event } from '../../../../core/d3-constants';

export function PaintFilterItem(mouse, data) {
    let manager = this,
        { options } = manager,
        { config } = options,
        { ranges } = config,
        point = data.point,
        event = d3_event();

    if (ranges[point].disabled) {
        ResetHighlightItem.call(manager, ...arguments, true);
        DisableItem.apply(manager, arguments);
    } else if (event) {
        if (event.touches) {
            ResetHighlightItem.call(manager, ...arguments, true);
        } else {
            HighlightItem.apply(manager, arguments);
            HighlightSeries.call(manager, ...arguments, true);
        }
    }
}
